# Now the SAME racy body but with a REAL write lock (subclass the threadsafe lock in)
class RacyButLocked(RacyService):
    def __init__(self):
        super().__init__(); self._rw = ReadWriteLock()
    from contextlib import contextmanager
    @contextmanager
    def _write_lock(self):
        with self._rw.write(): yield
    @contextmanager
    def _read_lock(self):
        with self._rw.read(): yield

